'use client'

import { useState, useRef, useEffect } from 'react'
import { supabase } from '@/lib/supabase'
import type { Quote } from '@/types'

// ── Tag color assignment (light theme) ─────────────────────────────────────

const TAG_PALETTES = [
  'bg-blue-100 text-blue-700 border-blue-200',
  'bg-violet-100 text-violet-700 border-violet-200',
  'bg-emerald-100 text-emerald-700 border-emerald-200',
  'bg-amber-100 text-amber-800 border-amber-200',
  'bg-rose-100 text-rose-700 border-rose-200',
  'bg-teal-100 text-teal-700 border-teal-200',
  'bg-indigo-100 text-indigo-700 border-indigo-200',
  'bg-orange-100 text-orange-700 border-orange-200',
]

export function tagColor(tag: string): string {
  let hash = 0
  for (let i = 0; i < tag.length; i++) {
    hash = (hash * 31 + tag.charCodeAt(i)) & 0xffffffff
  }
  return TAG_PALETTES[Math.abs(hash) % TAG_PALETTES.length]
}

// ── Copy button ─────────────────────────────────────────────────────────────

function CopyButton({ text }: { text: string }) {
  const [copied, setCopied] = useState(false)

  async function handleCopy() {
    await navigator.clipboard.writeText(text)
    setCopied(true)
    setTimeout(() => setCopied(false), 2000)
  }

  return (
    <button
      onClick={handleCopy}
      title="Copy quote"
      className="flex items-center gap-1 text-xs text-fog-500 hover:text-navy-600 bg-fog-100 hover:bg-fog-200 px-2 py-1 rounded-full transition-all"
    >
      {copied ? (
        <>
          <svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 20 20" fill="currentColor" className="w-3 h-3 text-emerald-600">
            <path fillRule="evenodd" d="M16.704 4.153a.75.75 0 0 1 .143 1.052l-8 10.5a.75.75 0 0 1-1.127.075l-4.5-4.5a.75.75 0 0 1 1.06-1.06l3.894 3.893 7.48-9.817a.75.75 0 0 1 1.05-.143Z" clipRule="evenodd" />
          </svg>
          <span className="text-emerald-600">Copied</span>
        </>
      ) : (
        <>
          <svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 20 20" fill="currentColor" className="w-3 h-3">
            <path d="M7 3.5A1.5 1.5 0 0 1 8.5 2h3.879a1.5 1.5 0 0 1 1.06.44l3.122 3.12A1.5 1.5 0 0 1 17 6.622V12.5a1.5 1.5 0 0 1-1.5 1.5h-1v-3.379a3 3 0 0 0-.879-2.121L10.5 5.379A3 3 0 0 0 8.379 4.5H7v-1Z" />
            <path d="M4.5 6A1.5 1.5 0 0 0 3 7.5v9A1.5 1.5 0 0 0 4.5 18h7a1.5 1.5 0 0 0 1.5-1.5v-5.879a1.5 1.5 0 0 0-.44-1.06L9.44 6.439A1.5 1.5 0 0 0 8.378 6H4.5Z" />
          </svg>
          Copy
        </>
      )}
    </button>
  )
}

// ── Tag input ───────────────────────────────────────────────────────────────

function TagInput({
  tags,
  onChange,
}: {
  tags: string[]
  onChange: (tags: string[]) => void
}) {
  const [input, setInput] = useState('')
  const inputRef = useRef<HTMLInputElement>(null)

  function addTag(raw: string) {
    const tag = raw.trim().toLowerCase().replace(/\s+/g, '-')
    if (!tag || tags.includes(tag)) {
      setInput('')
      return
    }
    onChange([...tags, tag])
    setInput('')
  }

  function handleKeyDown(e: React.KeyboardEvent<HTMLInputElement>) {
    if (e.key === 'Enter' || e.key === ',') {
      e.preventDefault()
      addTag(input)
    }
    if (e.key === 'Backspace' && !input && tags.length > 0) {
      onChange(tags.slice(0, -1))
    }
  }

  return (
    <div
      className="flex flex-wrap gap-1.5 items-center min-h-8 px-2 py-1.5 bg-fog-100 border border-fog-300 rounded-lg cursor-text"
      onClick={() => inputRef.current?.focus()}
    >
      {tags.map(tag => (
        <span
          key={tag}
          className={`inline-flex items-center gap-1 text-xs px-2 py-0.5 rounded-full border ${tagColor(tag)}`}
        >
          {tag}
          <button
            onClick={e => { e.stopPropagation(); onChange(tags.filter(t => t !== tag)) }}
            className="hover:opacity-70 ml-0.5 leading-none"
          >
            ×
          </button>
        </span>
      ))}
      <input
        ref={inputRef}
        value={input}
        onChange={e => setInput(e.target.value)}
        onKeyDown={handleKeyDown}
        onBlur={() => { if (input.trim()) addTag(input) }}
        placeholder={tags.length === 0 ? 'Add tags…' : ''}
        className="flex-1 min-w-[80px] bg-transparent text-xs text-navy-800 placeholder:text-fog-400 outline-none"
      />
    </div>
  )
}

// ── Quote widget ────────────────────────────────────────────────────────────

function QuoteWidget({
  quote,
  onUpdate,
  onDelete,
}: {
  quote: Quote
  onUpdate: (updated: Quote) => void
  onDelete: (id: string) => void
}) {
  const [editing, setEditing] = useState(false)
  const [showFull, setShowFull] = useState(false)
  const [editText, setEditText] = useState(quote.quote_text)
  const [editPage, setEditPage] = useState(quote.page_number?.toString() ?? '')
  const [editTags, setEditTags] = useState<string[]>(quote.tags ?? [])
  const [saving, setSaving] = useState(false)

  const isLong = quote.quote_text.length > 220
  const displayText = isLong && !showFull
    ? quote.quote_text.slice(0, 220).trim() + '…'
    : quote.quote_text

  async function handleSaveEdit() {
    setSaving(true)
    const updates = {
      quote_text: editText.trim(),
      page_number: editPage ? Number(editPage) : null,
      tags: editTags,
    }
    const { data, error } = await supabase
      .from('quotes')
      .update(updates)
      .eq('id', quote.id)
      .select()
      .single()
    if (!error && data) {
      onUpdate({ ...data as Quote, tags: (data as Quote).tags ?? [] })
    }
    setSaving(false)
    setEditing(false)
  }

  if (editing) {
    return (
      <div className="bg-white rounded-xl border-2 border-navy-300 shadow-sm p-4 space-y-3">
        <textarea
          autoFocus
          value={editText}
          onChange={e => setEditText(e.target.value)}
          rows={4}
          className="w-full resize-none bg-fog-50 border border-fog-300 rounded-lg px-3 py-2.5 text-sm text-navy-900 leading-relaxed placeholder:text-fog-400 focus:outline-none focus:ring-2 focus:ring-navy-500/20 transition-all"
        />
        <div className="flex gap-2 items-center">
          <label className="text-sm text-fog-600 shrink-0">p.</label>
          <input
            type="number"
            min={1}
            value={editPage}
            onChange={e => setEditPage(e.target.value)}
            placeholder="—"
            className="w-16 bg-fog-100 border border-fog-300 rounded-lg px-2 py-2 text-sm text-navy-800 focus:outline-none focus:ring-2 focus:ring-navy-500/20 transition-all"
          />
        </div>
        <TagInput tags={editTags} onChange={setEditTags} />
        <div className="flex gap-2 justify-end">
          <button
            onClick={() => {
              setEditing(false)
              setEditText(quote.quote_text)
              setEditPage(quote.page_number?.toString() ?? '')
              setEditTags(quote.tags ?? [])
            }}
            className="text-sm text-fog-600 hover:text-navy-700 px-3 py-1.5 rounded-lg transition-colors"
          >
            Cancel
          </button>
          <button
            onClick={handleSaveEdit}
            disabled={saving || !editText.trim()}
            className="bg-navy-700 hover:bg-navy-800 text-white px-4 py-2 rounded-full text-sm font-medium transition-all disabled:opacity-40"
          >
            {saving ? 'Saving…' : 'Save'}
          </button>
        </div>
      </div>
    )
  }

  return (
    <div className="bg-white rounded-xl border border-fog-300 shadow-sm p-4 group hover:border-fog-400 hover:shadow-md transition-all">
      {/* Quote text */}
      <p className="text-sm text-navy-900 italic leading-relaxed mb-3">
        &ldquo;{displayText}&rdquo;
        {isLong && (
          <button
            onClick={() => setShowFull(f => !f)}
            className="ml-1.5 text-xs text-navy-400 hover:text-navy-600 not-italic transition-colors"
          >
            {showFull ? '— less' : '… more'}
          </button>
        )}
      </p>

      {/* Metadata row: page + tags + actions */}
      <div className="flex items-center gap-2 flex-wrap">
        {quote.page_number != null && (
          <span className="text-xs text-fog-500 font-mono bg-fog-100 px-1.5 py-0.5 rounded border border-fog-300">
            p.{quote.page_number}
          </span>
        )}
        {(quote.tags ?? []).map(tag => (
          <span
            key={tag}
            className={`text-xs px-2 py-0.5 rounded-full border ${tagColor(tag)}`}
          >
            {tag}
          </span>
        ))}

        {/* Actions */}
        <div className="ml-auto flex items-center gap-1 opacity-0 group-hover:opacity-100 transition-opacity">
          <CopyButton text={quote.quote_text} />
          <button
            onClick={() => setEditing(true)}
            className="p-1.5 text-fog-400 hover:text-navy-600 rounded transition-colors"
            title="Edit"
          >
            <svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 20 20" fill="currentColor" className="w-3.5 h-3.5">
              <path d="M2.695 14.763l-1.262 3.154a.5.5 0 0 0 .65.65l3.155-1.262a4 4 0 0 0 1.343-.885L17.5 5.5a2.121 2.121 0 0 0-3-3L3.58 13.42a4 4 0 0 0-.885 1.343Z" />
            </svg>
          </button>
          <button
            onClick={() => onDelete(quote.id)}
            className="p-1.5 text-fog-400 hover:text-rose-500 rounded transition-colors"
            title="Delete"
          >
            <svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 20 20" fill="currentColor" className="w-3.5 h-3.5">
              <path fillRule="evenodd" d="M8.75 1A2.75 2.75 0 0 0 6 3.75v.443c-.795.077-1.584.176-2.365.298a.75.75 0 1 0 .23 1.482l.149-.022.841 10.518A2.75 2.75 0 0 0 7.596 19h4.807a2.75 2.75 0 0 0 2.742-2.53l.841-10.52.149.023a.75.75 0 0 0 .23-1.482A41.03 41.03 0 0 0 14 4.193V3.75A2.75 2.75 0 0 0 11.25 1h-2.5ZM10 4c.84 0 1.673.025 2.5.075V3.75c0-.69-.56-1.25-1.25-1.25h-2.5c-.69 0-1.25.56-1.25 1.25v.325C8.327 4.025 9.16 4 10 4ZM8.58 7.72a.75.75 0 0 0-1.5.06l.3 7.5a.75.75 0 1 0 1.5-.06l-.3-7.5Zm4.34.06a.75.75 0 1 0-1.5-.06l-.3 7.5a.75.75 0 1 0 1.5.06l.3-7.5Z" clipRule="evenodd" />
            </svg>
          </button>
        </div>
      </div>
    </div>
  )
}

// ── Main Quotes component ───────────────────────────────────────────────────

interface Props {
  bookId: string
  quotes: Quote[]
  onUpdate: (quotes: Quote[]) => void
}

export default function Quotes({ bookId, quotes, onUpdate }: Props) {
  const [addOpen, setAddOpen] = useState(false)
  const [addText, setAddText] = useState('')
  const [addPage, setAddPage] = useState('')
  const [addTags, setAddTags] = useState<string[]>([])
  const [adding, setAdding] = useState(false)

  // Sort by page number (nulls last), then creation time
  const sorted = [...quotes].sort((a, b) => {
    if (a.page_number == null && b.page_number == null) return 0
    if (a.page_number == null) return 1
    if (b.page_number == null) return -1
    return a.page_number - b.page_number
  })

  async function handleAdd() {
    if (!addText.trim()) return
    setAdding(true)
    const { data, error } = await supabase
      .from('quotes')
      .insert({
        book_id: bookId,
        quote_text: addText.trim(),
        page_number: addPage ? Number(addPage) : null,
        tags: addTags,
        heading_id: null,
        sort_order: null,
      })
      .select()
      .single()
    if (!error && data) {
      const newQuote = { ...data as Quote, tags: (data as Quote).tags ?? [] }
      onUpdate([...quotes, newQuote])
      setAddText('')
      setAddPage('')
      setAddTags([])
      setAddOpen(false)
    }
    setAdding(false)
  }

  function handleUpdate(updated: Quote) {
    onUpdate(quotes.map(q => q.id === updated.id ? updated : q))
  }

  async function handleDelete(id: string) {
    await supabase.from('quotes').delete().eq('id', id)
    onUpdate(quotes.filter(q => q.id !== id))
  }

  return (
    <div className="space-y-3">
      {/* Add quote form */}
      {addOpen ? (
        <div className="bg-white rounded-xl border-2 border-navy-300 shadow-sm p-4 space-y-3">
          <textarea
            autoFocus
            value={addText}
            onChange={e => setAddText(e.target.value)}
            placeholder="Paste or type quote text…"
            rows={3}
            className="w-full resize-none bg-fog-50 border border-fog-300 rounded-lg px-3 py-2.5 text-sm text-navy-900 leading-relaxed placeholder:text-fog-400 focus:outline-none focus:ring-2 focus:ring-navy-500/20 transition-all"
          />
          <div className="flex gap-2 items-center">
            <label className="text-sm text-fog-600 shrink-0">p.</label>
            <input
              type="number"
              min={1}
              value={addPage}
              onChange={e => setAddPage(e.target.value)}
              placeholder="—"
              className="w-16 bg-fog-100 border border-fog-300 rounded-lg px-2 py-2 text-sm text-navy-800 focus:outline-none focus:ring-2 focus:ring-navy-500/20 transition-all"
            />
          </div>
          <TagInput tags={addTags} onChange={setAddTags} />
          <div className="flex gap-2 justify-end">
            <button
              onClick={() => { setAddOpen(false); setAddText(''); setAddPage(''); setAddTags([]) }}
              className="text-sm text-fog-600 hover:text-navy-700 px-3 py-1.5 rounded-lg transition-colors"
            >
              Cancel
            </button>
            <button
              onClick={handleAdd}
              disabled={adding || !addText.trim()}
              className="bg-navy-700 hover:bg-navy-800 text-white px-4 py-2 rounded-full text-sm font-medium transition-all disabled:opacity-40"
            >
              {adding ? 'Adding…' : 'Add quote'}
            </button>
          </div>
        </div>
      ) : (
        <button
          onClick={() => setAddOpen(true)}
          className="w-full text-left text-sm text-fog-500 hover:text-navy-700 border border-dashed border-fog-400 hover:border-navy-300 rounded-xl px-4 py-3 transition-all hover:bg-white"
        >
          + Add quote
        </button>
      )}

      {/* Empty state */}
      {sorted.length === 0 && !addOpen && (
        <div className="text-center py-12 text-fog-400">
          <p className="text-3xl mb-3 opacity-40">❝</p>
          <p className="text-sm">No quotes yet. Add your first passage.</p>
        </div>
      )}

      {/* Quote list */}
      {sorted.map(quote => (
        <QuoteWidget
          key={quote.id}
          quote={quote}
          onUpdate={handleUpdate}
          onDelete={handleDelete}
        />
      ))}
    </div>
  )
}

'use client'

import { Suspense, useState, useEffect, useCallback } from 'react'
import { useRouter, useSearchParams } from 'next/navigation'
import { format, parseISO } from 'date-fns'
import { supabase } from '@/lib/supabase'
import { cacheBooks, getCachedBooks } from '@/lib/localCache'
import { getPendingBooks, processQueue } from '@/lib/syncQueue'
import {
  DndContext,
  closestCenter,
  DragEndEvent,
  DragOverlay,
  DragStartEvent,
  PointerSensor,
  useDroppable,
  useSensor,
  useSensors,
} from '@dnd-kit/core'
import {
  SortableContext,
  useSortable,
  verticalListSortingStrategy,
  arrayMove,
} from '@dnd-kit/sortable'
import { CSS } from '@dnd-kit/utilities'
import AddItemModal from '@/components/AddItemModal'
import DetailModal from '@/components/DetailModal'
import GlobalSearch from '@/components/GlobalSearch'
import type { Book } from '@/types'

const READING_SECTION = '__reading-now__'
const QUEUE_SECTION = '__next-up__'

// ── Drag handle ────────────────────────────────────────────────────────────────

function DragHandle() {
  return (
    <svg width="12" height="16" viewBox="0 0 12 16" fill="currentColor">
      <circle cx="4" cy="3" r="1.5" />
      <circle cx="8" cy="3" r="1.5" />
      <circle cx="4" cy="8" r="1.5" />
      <circle cx="8" cy="8" r="1.5" />
      <circle cx="4" cy="13" r="1.5" />
      <circle cx="8" cy="13" r="1.5" />
    </svg>
  )
}

// ── Complete check button ──────────────────────────────────────────────────────

function CompleteButton({ onClick, loading = false }: { onClick: () => void; loading?: boolean }) {
  return (
    <button
      onClick={e => { e.stopPropagation(); onClick() }}
      disabled={loading}
      className="w-7 h-7 flex items-center justify-center rounded-full text-fog-400 hover:text-white hover:bg-navy-700 transition-all disabled:opacity-40 shrink-0"
      title="Mark complete"
    >
      {loading ? (
        <span className="text-[10px]">…</span>
      ) : (
        <svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 20 20" fill="currentColor" className="w-3.5 h-3.5">
          <path fillRule="evenodd" d="M16.704 4.153a.75.75 0 0 1 .143 1.052l-8 10.5a.75.75 0 0 1-1.127.075l-4.5-4.5a.75.75 0 0 1 1.06-1.06l3.894 3.893 7.48-9.817a.75.75 0 0 1 1.05-.143Z" clipRule="evenodd" />
        </svg>
      )}
    </button>
  )
}

// ── Sortable book row (Reading Now / Next Up) ──────────────────────────────────

function SortableBookRow({
  book,
  onOpenDetail,
  onComplete,
  onMoveUp,
}: {
  book: Book
  onOpenDetail: () => void
  onComplete: (book: Book) => void
  onMoveUp?: () => void
}) {
  const { attributes, listeners, setNodeRef, transform, transition, isDragging } = useSortable({
    id: book.id,
  })

  const style = {
    transform: CSS.Transform.toString(transform),
    transition,
    opacity: isDragging ? 0.3 : 1,
  }

  const pct = book.total_pages && book.total_pages > 0
    ? Math.round(((book.current_page ?? 0) / book.total_pages) * 100)
    : 0
  const isQueued = book.status === 'queued' || book.status === 'paused'

  return (
    <div
      ref={setNodeRef}
      style={style}
      className="bg-white rounded-xl border border-fog-300 shadow-sm hover:border-fog-400 hover:shadow-md transition-all flex items-center gap-3 px-3 py-3"
    >
      {/* Drag handle */}
      <button
        {...attributes}
        {...listeners}
        className="text-fog-300 hover:text-fog-500 cursor-grab active:cursor-grabbing shrink-0 touch-none transition-colors"
        aria-label="Drag to reorder"
      >
        <DragHandle />
      </button>

      {/* Clickable content */}
      <button
        onClick={onOpenDetail}
        className="flex-1 min-w-0 text-left"
      >
        <p className="font-medium text-navy-900 truncate text-sm leading-snug">{book.title}</p>
        {book.author && (
          <p className="text-xs text-fog-500 mt-0.5 truncate">{book.author}</p>
        )}
        {!isQueued && book.total_pages && book.total_pages > 0 && (
          <div className="flex items-center gap-2 mt-1.5">
            <div className="w-28 bg-fog-200 rounded-full h-1.5">
              <div
                className="bg-gradient-to-r from-[#a8e063] to-[#2d6a4f] h-1.5 rounded-full transition-all"
                style={{ width: `${pct}%` }}
              />
            </div>
            <span className="text-xs text-fog-400">
              p.{book.current_page ?? 0}/{book.total_pages}
            </span>
          </div>
        )}
      </button>

      {/* Action */}
      {onMoveUp ? (
        <button
          onClick={e => { e.stopPropagation(); onMoveUp() }}
          className="text-xs text-fog-500 hover:text-navy-700 px-2.5 py-1 rounded-full bg-fog-100 hover:bg-navy-100 transition-all shrink-0"
        >
          Start
        </button>
      ) : (
        <CompleteButton onClick={() => onComplete(book)} />
      )}
    </div>
  )
}

// ── Drag overlay ───────────────────────────────────────────────────────────────

function BookDragOverlay({ book }: { book: Book }) {
  return (
    <div className="bg-white rounded-xl border border-navy-200 shadow-[0_12px_40px_rgba(14,30,53,0.15)] px-3 py-3 flex items-center gap-3 cursor-grabbing opacity-95">
      <div className="text-fog-300">
        <DragHandle />
      </div>
      <div className="flex-1 min-w-0">
        <p className="font-medium text-navy-900 truncate text-sm">{book.title}</p>
        {book.author && <p className="text-xs text-fog-500 mt-0.5">{book.author}</p>}
      </div>
    </div>
  )
}

// ── Droppable section ──────────────────────────────────────────────────────────

function DroppableSection({
  id,
  children,
  className = '',
}: {
  id: string
  children: React.ReactNode
  className?: string
}) {
  const { setNodeRef, isOver } = useDroppable({ id })
  return (
    <div
      ref={setNodeRef}
      className={`${className} rounded-xl transition-all ${isOver ? 'ring-2 ring-navy-300/40' : ''}`}
    >
      {children}
    </div>
  )
}

// ── Article card ───────────────────────────────────────────────────────────────

function ArticleCard({
  book,
  onOpenDetail,
  onDone,
}: {
  book: Book
  onOpenDetail: () => void
  onDone: () => void
}) {
  const [loading, setLoading] = useState(false)

  async function handleDone() {
    setLoading(true)
    await onDone()
    setLoading(false)
  }

  const meta = [book.publication, book.article_date].filter(Boolean).join(' · ')

  return (
    <div className="bg-white rounded-xl border border-fog-300 shadow-sm hover:border-fog-400 hover:shadow-md transition-all flex items-center gap-3 px-4 py-3">
      <button onClick={onOpenDetail} className="flex-1 min-w-0 text-left">
        <p className="font-medium text-navy-900 truncate text-sm leading-snug">{book.title}</p>
        <p className="text-xs text-fog-500 mt-0.5 truncate">
          {[book.author, meta].filter(Boolean).join(' · ') || <span className="italic opacity-60">Article</span>}
        </p>
      </button>
      <CompleteButton onClick={handleDone} loading={loading} />
    </div>
  )
}

// ── Podcast card ───────────────────────────────────────────────────────────────

function PodcastCard({
  book,
  onOpenDetail,
  onDone,
}: {
  book: Book
  onOpenDetail: () => void
  onDone: () => void
}) {
  const [loading, setLoading] = useState(false)

  async function handleDone() {
    setLoading(true)
    await onDone()
    setLoading(false)
  }

  const meta = [book.show_title, book.air_date].filter(Boolean).join(' · ')

  return (
    <div className="bg-white rounded-xl border border-fog-300 shadow-sm hover:border-fog-400 hover:shadow-md transition-all flex items-center gap-3 px-4 py-3">
      <button onClick={onOpenDetail} className="flex-1 min-w-0 text-left">
        <p className="font-medium text-navy-900 truncate text-sm leading-snug">{book.title}</p>
        <p className="text-xs text-fog-500 mt-0.5 truncate">
          {meta || <span className="italic opacity-60">Podcast</span>}
        </p>
      </button>
      <CompleteButton onClick={handleDone} loading={loading} />
    </div>
  )
}

// ── Confirm complete modal ─────────────────────────────────────────────────────

function ConfirmCompleteModal({
  book,
  onClose,
  onConfirm,
}: {
  book: Book
  onClose: () => void
  onConfirm: () => void
}) {
  const [loading, setLoading] = useState(false)

  async function handleConfirm() {
    setLoading(true)
    await onConfirm()
    setLoading(false)
  }

  return (
    <div
      className="fixed inset-0 bg-navy-900/40 backdrop-blur-sm flex items-center justify-center z-50 p-4"
      onClick={e => { if (e.target === e.currentTarget) onClose() }}
    >
      <div className="bg-white rounded-2xl shadow-[0_24px_80px_rgba(14,30,53,0.2)] w-full max-w-sm p-6">
        <h2 className="font-semibold text-navy-900 mb-2">Finish &ldquo;{book.title}&rdquo;?</h2>
        <p className="text-sm text-fog-600 leading-relaxed">
          This will mark the book as completed and move it to your finished list.
        </p>
        <div className="flex gap-3 mt-5">
          <button
            onClick={onClose}
            className="flex-1 bg-fog-100 hover:bg-fog-200 text-navy-700 px-4 py-2.5 rounded-full text-sm font-medium transition-all"
          >
            Cancel
          </button>
          <button
            onClick={handleConfirm}
            disabled={loading}
            className="flex-1 bg-navy-700 hover:bg-navy-800 text-white px-4 py-2.5 rounded-full text-sm font-semibold transition-all disabled:opacity-50"
          >
            {loading ? 'Finishing…' : 'Yes, finish it'}
          </button>
        </div>
      </div>
    </div>
  )
}

// ── Completed section ──────────────────────────────────────────────────────────

function CompletedSection({
  title,
  items,
  onOpenDetail,
}: {
  title: string
  items: Book[]
  onOpenDetail: (book: Book) => void
}) {
  const [showAll, setShowAll] = useState(false)
  const sorted = [...items].sort((a, b) =>
    (b.date_finished ?? b.created_at ?? '').localeCompare(a.date_finished ?? a.created_at ?? '')
  )
  const visible = showAll ? sorted : sorted.slice(0, 3)
  const hidden = sorted.length - 3

  return (
    <section>
      <h2 className="text-[11px] font-bold uppercase tracking-widest text-[#cc5500] mb-3">
        {title}
      </h2>
      <div className="space-y-1.5">
        {visible.map(book => (
          <button
            key={book.id}
            onClick={() => onOpenDetail(book)}
            className="w-full text-left bg-white rounded-xl border border-fog-300 shadow-sm px-4 py-3 flex items-center gap-3 hover:border-fog-400 hover:shadow-md transition-all group"
          >
            <div className="flex-1 min-w-0">
              <p className="text-sm font-medium text-navy-800 truncate group-hover:text-navy-900">
                {book.title}
              </p>
              {book.author && (
                <p className="text-xs text-fog-400 mt-0.5 truncate">{book.author}</p>
              )}
            </div>
            {book.date_finished && (
              <span className="text-xs text-fog-400 shrink-0">
                {format(parseISO(book.date_finished), 'MMM d, yyyy')}
              </span>
            )}
            <span className="text-xs text-ember-600 font-medium shrink-0">✓</span>
          </button>
        ))}

        {hidden > 0 && (
          <button
            onClick={() => setShowAll(s => !s)}
            className="w-full text-center text-xs text-fog-500 hover:text-navy-600 py-2 transition-colors"
          >
            {showAll ? 'Show less' : `Show ${hidden} more`}
          </button>
        )}
      </div>
    </section>
  )
}

// ── Section header ─────────────────────────────────────────────────────────────

function SectionHeader({ children }: { children: React.ReactNode }) {
  return (
    <h2 className="text-[11px] font-bold uppercase tracking-widest text-[#cc5500] mb-3">
      {children}
    </h2>
