'use client'

import { useState, useEffect } from 'react'
import { useRouter } from 'next/navigation'
import { format, parseISO } from 'date-fns'
import { supabase } from '@/lib/supabase'
import type { Book } from '@/types'

function sortRecent(items: Book[]) {
  return [...items].sort((a, b) =>
    (b.date_finished ?? b.created_at ?? '').localeCompare(a.date_finished ?? a.created_at ?? '')
  )
}

function CompletedGroup({
  emoji,
  heading,
  items,
  onOpen,
}: {
  emoji: string
  heading: string
  items: Book[]
  onOpen: (book: Book) => void
}) {
  if (items.length === 0) return null
  const sorted = sortRecent(items)

  return (
    <section>
      <h2 className="text-[11px] font-bold uppercase tracking-widest text-[#cc5500] mb-3">
        {emoji} {heading}
      </h2>
      <div className="space-y-1.5">
        {sorted.map(book => (
          <button
            key={book.id}
            onClick={() => onOpen(book)}
            className="w-full text-left bg-white rounded-xl border border-fog-300 shadow-sm px-4 py-3 flex items-center gap-3 hover:border-fog-400 hover:shadow-md transition-all group"
          >
            <div className="flex-1 min-w-0">
              <p className="text-sm font-medium text-navy-800 truncate group-hover:text-navy-900">
                {book.title}
              </p>
              {book.author && (
                <p className="text-xs text-fog-400 mt-0.5 truncate">{book.author}</p>
              )}
            </div>
            {book.date_finished && (
              <span className="text-xs text-fog-400 shrink-0">
                {format(parseISO(book.date_finished), 'MMM d, yyyy')}
              </span>
            )}
            <span className="text-xs text-ember-600 font-medium shrink-0">✓</span>
          </button>
        ))}
      </div>
    </section>
  )
}

export default function CompletedPage() {
  const router = useRouter()
  const [books, setBooks] = useState<Book[]>([])
  const [loading, setLoading] = useState(true)

  useEffect(() => {
    async function load() {
      const { data } = await supabase
        .from('books')
        .select('*')
        .eq('status', 'completed')
        .order('date_finished', { ascending: false, nullsFirst: false })
        .order('created_at', { ascending: false })
      setBooks((data as Book[]) ?? [])
      setLoading(false)
    }
    load()
  }, [])

  function openDetail(book: Book) {
    router.push(`/?book=${book.id}&tab=outline`)
  }

  const completedBooks = books.filter(b => b.type === 'book')
  const completedArticles = books.filter(b => b.type === 'article')
  const completedPodcasts = books.filter(b => b.type === 'podcast')

  return (
    <div className="min-h-screen bg-fog-200">
      {/* Header */}
      <header className="bg-white/80 border-b border-fog-300 sticky top-0 z-10 backdrop-blur-xl">
        <div className="max-w-4xl mx-auto px-6 py-4 flex items-center gap-4">
          <button
            onClick={() => router.push('/')}
            className="text-fog-500 hover:text-navy-700 transition-colors flex items-center gap-1.5 text-sm"
          >
            <svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 20 20" fill="currentColor" className="w-4 h-4">
              <path fillRule="evenodd" d="M17 10a.75.75 0 0 1-.75.75H5.612l4.158 3.96a.75.75 0 1 1-1.04 1.08l-5.5-5.25a.75.75 0 0 1 0-1.08l5.5-5.25a.75.75 0 1 1 1.04 1.08L5.612 9.25H16.25A.75.75 0 0 1 17 10Z" clipRule="evenodd" />
            </svg>
            Back
          </button>
          <h1 className="text-lg font-bold tracking-tight" style={{ color: '#191970' }}>
            Completed Media
          </h1>
        </div>
      </header>

      <main className="max-w-4xl mx-auto px-6 py-8 space-y-8">
        {loading ? (
          <div className="text-center py-16 text-fog-400 text-sm">Loading…</div>
        ) : books.length === 0 ? (
          <div className="text-center py-16 text-fog-400 text-sm">No completed items yet.</div>
        ) : (
          <>
            <CompletedGroup emoji="📚" heading="Books" items={completedBooks} onOpen={openDetail} />
            <CompletedGroup emoji="📰" heading="Articles" items={completedArticles} onOpen={openDetail} />
            <CompletedGroup emoji="🎙️" heading="Podcasts" items={completedPodcasts} onOpen={openDetail} />
          </>
        )}
      </main>
    </div>
  )
}

